(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[55175],{84202:function(e,n,o){(window.__NEXT_P=window.__NEXT_P||[]).push(["/en/blog/announcements/appdynamics-newrelic-opbeat-sphinx",function(){return o(55722)}])},55722:function(e,n,o){"use strict";o.r(n),o.d(n,{__N_SSG:function(){return p}});var t=o(26042),i=o(69396),a=o(85893),s=o(48863),r=o(11151);function d(e){var n=Object.assign({blockquote:"blockquote",p:"p",a:"a"},(0,r.ah)(),e.components);return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)(n.blockquote,{children:["\n",(0,a.jsx)(n.p,{children:"Foundation Announces Dates for Node.js Interactive Conferences in Amsterdam and Austin, Texas"}),"\n"]}),"\n",(0,a.jsxs)(n.p,{children:["SAN FRANCISCO, Mar. 9, 2016 — The ",(0,a.jsx)(n.a,{href:"https://foundation.nodejs.org/",children:"Node.js Foundation"}),", a community-led and industry-backed consortium to advance the development of the Node.js platform, today announced AppDynamics, New Relic, Opbeat and Sphinx are joining the Foundation as Silver Members to continue to sustain and grow the Node.js platform."]}),"\n",(0,a.jsx)(n.p,{children:"Many of the new members are within the application performance management industry, both established and up-and-coming vendors. Application performance management is an essential part of any infrastructure and there is a need across public, private and hybrid clouds to ensure that current and future products offer next-generation application performance with Node.js as a core component to the stability and potential of these offerings."}),"\n",(0,a.jsxs)(n.p,{children:["The new members have the opportunity to support a range of Foundation activities such as new training programs and user-focused events like the new, ongoing ",(0,a.jsx)(n.a,{href:"http://live.nodejs.org/",children:"Node.js Live"})," series and Node.js Interactive events. Expanding to Europe this year, Node.js Interactive will take place September 15-16 in Amsterdam, Netherlands; while the North America event will be held November 29-30, 2016, in Austin, Texas. More information on the conference to come."]}),"\n",(0,a.jsxs)(n.p,{children:["Node.js has grown tremendously in the last year with a total of ",(0,a.jsx)(n.a,{href:"https://www.npmjs.com/",children:"3.5 million"})," users and 100 percent year-over-year growth. It is becoming ubiquitous across numerous industries from financial services to media companies, and is heavily used by frontend, backend and IoT developers."]}),"\n",(0,a.jsx)(n.p,{children:"“While the popularity of Node.js has dramatically increased in recent years, the Foundation is committed to maintaining a stable, neutral and transparent ground to support continuation of the technology’s growth,” said Danese Cooper, Chairperson of the Node.js Foundation Board. “We are pleased to have AppDynamics, New Relic, Opbeat and Sphinx join the Foundation to help support both continued expansion for the technology and stability needs of the community.”"}),"\n",(0,a.jsx)(n.p,{children:"More About the New Members:"}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"http://www.appdynamics.com/",children:"AppDynamics"})," is the application intelligence company that provides real-time insights into application performance, user experience, and business outcomes with cloud, on-premises, and hybrid deployment flexibility. Seeing the growing popularity of Node.js as a platform for building fast and scalable web and mobile applications, AppDynamics created a Node.js monitoring solution built on their core APM platform. The solution helps customers monitor Node.js applications in real-time and diagnose performance bottlenecks while running in live production or development environments."]}),"\n",(0,a.jsx)(n.p,{children:"“Node.js is clearly taking off, and we’ve seen significant adoption of the platform in production for quite some time now, especially within the enterprise. We have participated in multiple Node.js events in the past, and look forward to continuing to support the longevity of this project, which is important to the developers that we serve,” said AppDynamics Chief Technology Officer and Senior Vice President of Product Management, Bhaskar Sunkara."}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"https://newrelic.com/",children:"New Relic"})," is a software analytics company that delivers real-time insights and helps companies securely monitor their production software in virtually any environment, without having to build or maintain dedicated infrastructure. New Relic’s agent helps pinpoint Node.js application performance issues across private, public or hybrid cloud environments."]}),"\n",(0,a.jsx)(n.p,{children:"“We're seeing huge growth in our Node.js application counts on a daily basis, from customers of all sizes - there's just as much interest from the Fortune 100 as there is from new startups. New Relic's engineers have been contributing to Node.js's core development for years, and we're excited to help accelerate its advancement and success even further by supporting the Node.js Foundation,\" said Tim Krajcar, Engineering Manager, Node.js Agent, New Relic."}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"https://opbeat.com/",children:"Opbeat"})," provides next-generation performance insights, specifically built for JavaScript developers. Opbeat maps production issues to the developers that write the code, leading to faster debugging and more coding. The young company recently launched ",(0,a.jsx)(n.a,{href:"https://opbeat.com/nodejs/",children:"full support for Node.js"}),"."]}),"\n",(0,a.jsx)(n.p,{children:"“We’re seeing massive interest in Opbeat within the Node community - from larger organizations to smaller start-ups - so we’re excited to join the Foundation to help support the community. At the end of the day, our customers are developers and we want to contribute to the increased popularity of Node amongst developers and CTOs,” said Rasmus Makwarth, Co-Founder and CEO of Opbeat."}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.a,{href:"http://sphinx.sg/",children:"Sphinx"})," was established in 2014 by experience Vietnamese developers from Silicon Valley with the aim to become the leading company on Node.js and the MEAN stack — the group has co-founded the Vietnamese Node.js and Angular.js communities. The consulting team helps take large-scale applications from the concept phase to production for some of the largest global enterprises and government departments."]}),"\n",(0,a.jsx)(n.p,{children:"“Becoming a silver member is a breakthrough for us, and gives us the opportunity to establish long-lasting relationships with companies that also share a common interest in the rapidly growing Node.js technology. We look forward to collaborating with other Foundation members and continuing to develop and support the open source community,” said Hai Luong, CEO and Co-Founder of Sphinx."}),"\n",(0,a.jsx)(n.p,{children:"About Node.js Foundation\nNode.js is used by tens of thousands of organizations in more than 200 countries and amasses more than 3.5 million active users per month. It is the runtime of choice for high-performance, low latency applications, powering everything from enterprise applications, robots, API engines, cloud stacks and mobile websites."}),"\n",(0,a.jsxs)(n.p,{children:["The Foundation is made up of a diverse group of companies including Platinum members Famous, IBM, Intel, Joyent, Microsoft, PayPal and Red Hat. Gold members include GoDaddy, NodeSource and Modulus/Progress Software, and Silver members include Apigee, AppDynamics, Codefresh, DigitalOcean, Fidelity, Groupon, nearForm, New Relic, npm, Opbeat, RisingStack, Sauce Labs, SAP, StrongLoop (an IBM company), Sphinx, YLD!, and Yahoo!. Get involved here: ",(0,a.jsx)(n.a,{href:"https://nodejs.org/",children:"https://nodejs.org"}),"."]}),"\n",(0,a.jsxs)(n.p,{children:["The Node.js Foundation is a Linux Foundation Project, which are independently funded software projects that harness the power of collaborative development to fuel innovation across industries and ecosystems. ",(0,a.jsx)(n.a,{href:"http://www.linuxfoundation.org/",children:"www.linuxfoundation.org"})]})]})}o(25675);var p=!0;n.default=(0,s.j)({MDXContent:function(){var e=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},n=Object.assign({},(0,r.ah)(),e.components).wrapper;return n?(0,a.jsx)(n,(0,i.Z)((0,t.Z)({},e),{children:(0,a.jsx)(d,(0,t.Z)({},e))})):d(e)},pageOpts:{filePath:"pages/en/blog/announcements/appdynamics-newrelic-opbeat-sphinx.md",route:"/en/blog/announcements/appdynamics-newrelic-opbeat-sphinx",frontMatter:{title:"AppDynamics, New Relic, Opbeat and Sphinx Join the Node.js Foundation as Silver Members",date:"2016-03-09T21:00:00.000Z",category:"announcements",slug:"appdynamics-newrelice-opbeat-sphinx",layout:"blog-post.hbs"},title:"AppDynamics, New Relic, Opbeat and Sphinx Join the Node.js Foundation as Silver Members"},pageNextRoute:"/en/blog/announcements/appdynamics-newrelic-opbeat-sphinx"})}},function(e){e.O(0,[48863,49774,92888,40179],function(){return e(e.s=84202)}),_N_E=e.O()}]);